const https = require('https');

// 从配置获取
const appId = 'cli_a92027f8bbb85bc6';
const appSecret = 'qHbubWguafLFd1NppHnXcdIDXf84WXl4';
const chatId = 'oc_4e3daa6139b1eb7beebec0de6dcef569';

// 1. 获取 tenant_access_token
function getTenantAccessToken() {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify({
      app_id: appId,
      app_secret: appSecret
    });

    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData)
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          if (result.code === 0) {
            resolve(result.tenant_access_token);
          } else {
              reject(new Error('获取 token 失败: ' + result.msg));
            }
        } catch (e) {
          reject(e);
        }
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

// 2. 获取消息列表
function getMessages(token) {
  return new Promise((resolve, reject) => {
    const now = Date.now();
    const oneHourAgo = now - 60 * 60 * 1000;

    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/im/v1/messages?container_id_type=chat&container_id=${chatId}&sort_type=ByCreateTimeAsc&sort_order=Descending`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          if (result.code === 0) {
            // 过滤过去1小时的消息
            const filtered = result.data.items.filter(msg => {
              const createTime = parseInt(msg.create_time);
              return createTime >= oneHourAgo;
            });
            resolve(filtered);
          } else {
            reject(new Error('获取消息失败: ' + result.msg));
          }
        } catch (e) {
          reject(e);
        }
      });
    });

    req.on('error', reject);
    req.end();
  });
}

// 主流程
async function main() {
  try {
    console.log('正在获取 tenant_access_token...');
    const token = await getTenantAccessToken();
    console.log('Token 获取成功');

    console.log('正在获取消息...');
    const messages = await getMessages(token);
    console.log(`获取到 ${messages.length} 条消息`);

    // 输出 JSON
    console.log(JSON.stringify(messages, null, 2);
  } catch (e) {
    console.error('错误:', e.message);
    process.exit(1);
  }
}

main();

